reference_solution:
def sort_scores(scores):
    if not scores:
        return []
    counts = [0] * 101
    for s in scores:
        counts[s] += 1
    result = []
    for i in range(101):
        result.extend([i] * counts[i])
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_mixed_scores(self):
        self.assertEqual(sort_scores([85, 92, 78, 90, 85, 60]), [60, 78, 85, 85, 90, 92])

    def test_boundary_scores(self):
        self.assertEqual(sort_scores([100, 0, 50]), [0, 50, 100])

    def test_all_same(self):
        self.assertEqual(sort_scores([70, 70, 70]), [70, 70, 70])

    def test_hidden_empty(self):
        self.assertEqual(sort_scores([]), [])

    def test_hidden_single(self):
        self.assertEqual(sort_scores([95]), [95])

    def test_hidden_already_sorted(self):
        self.assertEqual(sort_scores([10, 20, 30, 40, 50]), [10, 20, 30, 40, 50])

    def test_hidden_reverse_sorted(self):
        self.assertEqual(sort_scores([100, 75, 50, 25, 0]), [0, 25, 50, 75, 100])

    def test_hidden_duplicates_heavy(self):
        self.assertEqual(sort_scores([88, 88, 88, 88]), [88, 88, 88, 88])

    def test_hidden_min_max_only(self):
        self.assertEqual(sort_scores([0, 100, 0, 100]), [0, 0, 100, 100])

    def test_hidden_many_scores(self):
        scores = [55, 23, 99, 100, 0, 0, 45, 67, 89, 23, 55, 78, 12, 34, 56]
        expected = [0, 0, 12, 23, 23, 34, 45, 55, 55, 56, 67, 78, 89, 99, 100]
        self.assertEqual(sort_scores(scores), expected)

if __name__ == '__main__':
    unittest.main()
